obj_exists <- function(x) exists(x, envir = .GlobalEnv)

safe_get <- function(x, default = NULL) {
  if (exists(x, envir = .GlobalEnv)) get(x, envir = .GlobalEnv) else default
}

fmt_n <- function(x) {
  if (length(x) == 0 || is.na(x)) return("NA")
  formatC(as.integer(round(x)), format = "d", big.mark = ",")
}

fmt_num <- function(x, digits = 2) {
  if (length(x) == 0 || is.na(x)) return("NA")
  formatC(as.numeric(x), format = "f", digits = digits)
}

fmt_pct <- function(x, digits = 1) {
  if (length(x) == 0 || is.na(x)) return("NA")
  paste0(formatC(as.numeric(x), format = "f", digits = digits), "%")
}

fmt_p <- function(p) {
  if (length(p) == 0 || is.na(p)) return("NA")
  if (p < .001) return("< .001")
  paste0("= ", formatC(p, format = "f", digits = 3))
}

fmt_signed <- function(x, digits = 2) {
  if (length(x) == 0 || is.na(x)) return("NA")
  out <- formatC(abs(as.numeric(x)), format = "f", digits = digits)
  ifelse(x >= 0, paste0("+", out), paste0("-", out))
}

direction_word <- function(change_score, improvement_is_positive = TRUE) {
  if (is.na(change_score)) return("no clear")
  if (improvement_is_positive) {
    if (change_score > 0) return("greater")
    if (change_score < 0) return("lesser")
  } else {
    if (change_score < 0) return("greater")
    if (change_score > 0) return("lesser")
  }
  "similar"
}

