# Vector-safe formatters for mutate()
fmt_num_vec <- function(x, digits = 2) {
  ifelse(
    is.na(x),
    "NA",
    formatC(as.numeric(x), format = "f", digits = digits)
  )
}

fmt_p_vec <- function(p) {
  case_when(
    is.na(p) ~ "NA",
    p < .001 ~ "< .001",
    TRUE ~ paste0("= ", formatC(p, format = "f", digits = 3))
  )
}

