get_score_endpoint <- function(summary_df, cond, first_tp = NULL, last_tp = NULL) {
  if (is.null(summary_df) || nrow(summary_df) == 0) {
    return(tibble(first_mean = NA, last_mean = NA, improvement = NA, first_tp = NA, last_tp = NA))
  }
  
  d <- summary_df %>%
    filter(as.character(condition) == cond) %>%
    arrange(tp)
  
  if (!is.null(first_tp)) d_first <- d %>% filter(as.character(tp) == first_tp) else d_first <- d %>% slice(1)
  if (!is.null(last_tp))  d_last  <- d %>% filter(as.character(tp) == last_tp)  else d_last  <- d %>% slice(n())
  
  if (nrow(d_first) == 0 || nrow(d_last) == 0) {
    return(tibble(first_mean = NA, last_mean = NA, improvement = NA, first_tp = NA, last_tp = NA))
  }
  
  tibble(
    first_mean = d_first$mean[1],
    last_mean = d_last$mean[1],
    improvement = d_first$mean[1] - d_last$mean[1],
    first_tp = as.character(d_first$tp[1]),
    last_tp = as.character(d_last$tp[1])
  )
}

