split_summary <- function(df, score_col = NULL) {
  if (is.null(df) || nrow(df) == 0) {
    return(tibble(
      split_group = c("Low", "High"),
      n = NA_integer_,
      mean_pre = NA_real_,
      mean_post = NA_real_,
      mean_improve = NA_real_,
      mean_score = NA_real_
    ))
  }
  
  score_expr <- if (!is.null(score_col) && score_col %in% names(df)) {
    rlang::sym(score_col)
  } else {
    NULL
  }
  
  out <- df %>%
    group_by(split_group) %>%
    summarise(
      n = n(),
      mean_pre = mean(bdi_pre, na.rm = TRUE),
      mean_post = mean(bdi_post, na.rm = TRUE),
      mean_improve = mean(bdi_improve, na.rm = TRUE),
      .groups = "drop"
    )
  
  if (!is.null(score_expr)) {
    score_df <- df %>%
      group_by(split_group) %>%
      summarise(mean_score = mean(!!score_expr, na.rm = TRUE), .groups = "drop")
    out <- out %>% left_join(score_df, by = "split_group")
  } else {
    out$mean_score <- NA_real_
  }
  
  out
}

exp_split_sum <- split_summary(pt_exp_local, "expect_sum")
asc_split_sum <- split_summary(pt_asc_local, "asc_z")

get_split_row <- function(d, grp) {
  out <- d %>% filter(as.character(split_group) == grp)
  if (nrow(out) == 0) {
    tibble(
      split_group = grp,
      n = NA_integer_,
      mean_pre = NA_real_,
      mean_post = NA_real_,
      mean_improve = NA_real_,
      mean_score = NA_real_
    )
  } else {
    out[1, ]
  }
}

